/**
 * Daily Sync Job
 * 
 * Fetches data from GoHighLevel and stores it in the database
 * 
 * This job:
 * 1. Fetches contacts from GHL
 * 2. Fetches opportunities from GHL
 * 3. Stores sync results in the database
 * 4. Logs execution details
 */

import { GHLApiClient } from '../ghl/api-client';
import { JobContext, JobRunResult } from '../utils/job-runner';

export interface DailySyncResult {
  contactsCount: number;
  opportunitiesCount: number;
  pipelinesCount: number;
  syncedAt: string;
}

/**
 * Execute daily sync job
 */
export async function executeDailySync(context: JobContext): Promise<JobRunResult> {
  const { installationId, locationId, supabase } = context;

  console.log(`[daily_sync] Starting sync for location ${locationId}`);

  try {
    // Initialize GHL API client
    const ghlClient = new GHLApiClient(locationId);

    // Fetch data from GHL
    const [contacts, opportunities, pipelines] = await Promise.all([
      fetchContacts(ghlClient),
      fetchOpportunities(ghlClient),
      fetchPipelines(ghlClient),
    ]);

    console.log(`[daily_sync] Fetched ${contacts.length} contacts, ${opportunities.length} opportunities, ${pipelines.length} pipelines`);

    // Store sync results
    const syncResult: DailySyncResult = {
      contactsCount: contacts.length,
      opportunitiesCount: opportunities.length,
      pipelinesCount: pipelines.length,
      syncedAt: new Date().toISOString(),
    };

    // Save sync data to database
    await saveSyncData(supabase, installationId, locationId, {
      contacts,
      opportunities,
      pipelines,
    });

    // Log audit event
    await supabase.rpc('log_audit_event', {
      loc_id: locationId,
      evt_type: 'daily_sync_completed',
      evt_data: syncResult,
    });

    console.log(`[daily_sync] Sync completed successfully for location ${locationId}`);

    return {
      success: true,
      status: 'completed',
      message: 'Daily sync completed successfully',
      data: syncResult,
    };
  } catch (error) {
    console.error(`[daily_sync] Sync failed for location ${locationId}:`, error);

    // Log audit event for failure
    await supabase.rpc('log_audit_event', {
      loc_id: locationId,
      evt_type: 'daily_sync_failed',
      evt_data: {
        error: error instanceof Error ? error.message : 'Unknown error',
      },
    });

    return {
      success: false,
      status: 'failed',
      message: 'Daily sync failed',
      error: error instanceof Error ? error.message : 'Unknown error',
    };
  }
}

/**
 * Fetch contacts from GHL
 */
async function fetchContacts(ghlClient: GHLApiClient): Promise<any[]> {
  try {
    const response = await ghlClient.getContacts(100);
    return response.contacts || [];
  } catch (error) {
    console.error('[daily_sync] Failed to fetch contacts:', error);
    return [];
  }
}

/**
 * Fetch opportunities from GHL
 */
async function fetchOpportunities(ghlClient: GHLApiClient): Promise<any[]> {
  try {
    const response = await ghlClient.getOpportunities(undefined, 100);
    return response.opportunities || [];
  } catch (error) {
    console.error('[daily_sync] Failed to fetch opportunities:', error);
    return [];
  }
}

/**
 * Fetch pipelines from GHL
 */
async function fetchPipelines(ghlClient: GHLApiClient): Promise<any[]> {
  try {
    const response = await ghlClient.getPipelines();
    return response.pipelines || [];
  } catch (error) {
    console.error('[daily_sync] Failed to fetch pipelines:', error);
    return [];
  }
}

/**
 * Save sync data to database
 */
async function saveSyncData(
  supabase: any,
  installationId: string,
  locationId: string,
  data: {
    contacts: any[];
    opportunities: any[];
    pipelines: any[];
  }
): Promise<void> {
  try {
    // Store in a sync_data table (you may want to create this table)
    // For now, we'll just log the counts
    console.log(`[daily_sync] Saving sync data for location ${locationId}`);

    // Example: Store summary in a custom table
    const { error } = await supabase.from('sync_data').upsert({
      installation_id: installationId,
      location_id: locationId,
      contacts_count: data.contacts.length,
      opportunities_count: data.opportunities.length,
      pipelines_count: data.pipelines.length,
      synced_at: new Date().toISOString(),
      data: {
        contacts: data.contacts.slice(0, 10), // Store first 10 for reference
        opportunities: data.opportunities.slice(0, 10),
        pipelines: data.pipelines,
      },
    });

    if (error) {
      console.error('[daily_sync] Failed to save sync data:', error);
    }
  } catch (error) {
    console.error('[daily_sync] Error saving sync data:', error);
  }
}