/**
 * Job Runner Utility
 * 
 * Base utility for running background jobs with:
 * - Installation status checking
 * - Subscription status checking
 * - Error handling and logging
 * - Job execution tracking
 */

import { createClient, SupabaseClient } from '@supabase/supabase-js';

const supabaseUrl = process.env.NEXT_PUBLIC_SUPABASE_URL!;
const supabaseServiceKey = process.env.SUPABASE_SERVICE_ROLE_KEY!;

export type JobStatus = 'pending' | 'running' | 'completed' | 'failed' | 'skipped';

export interface JobRunResult {
  success: boolean;
  status: JobStatus;
  message: string;
  data?: any;
  error?: string;
}

export interface JobContext {
  installationId: string;
  locationId: string;
  jobName: string;
  supabase: SupabaseClient;
}

export interface JobConfig {
  jobName: string;
  description?: string;
  timeout?: number; // milliseconds
  retryAttempts?: number;
}

export class JobRunner {
  private supabase: SupabaseClient;
  private config: JobConfig;

  constructor(config: JobConfig) {
    this.supabase = createClient(supabaseUrl, supabaseServiceKey);
    this.config = {
      timeout: 300000, // 5 minutes default
      retryAttempts: 3,
      ...config,
    };
  }

  /**
   * Execute a job for all active installations
   */
  async executeForAllInstallations(
    jobFunction: (context: JobContext) => Promise<JobRunResult>
  ): Promise<{ total: number; successful: number; failed: number; skipped: number }> {
    console.log(`[${this.config.jobName}] Starting job execution for all installations`);

    // Get all active installations
    const installations = await this.getActiveInstallations();
    console.log(`[${this.config.jobName}] Found ${installations.length} active installations`);

    let successful = 0;
    let failed = 0;
    let skipped = 0;

    // Execute job for each installation
    for (const installation of installations) {
      try {
        const result = await this.executeForInstallation(
          installation.id,
          installation.location_id,
          jobFunction
        );

        if (result.status === 'completed') {
          successful++;
        } else if (result.status === 'skipped') {
          skipped++;
        } else {
          failed++;
        }
      } catch (error) {
        console.error(
          `[${this.config.jobName}] Error executing for installation ${installation.id}:`,
          error
        );
        failed++;
      }
    }

    console.log(
      `[${this.config.jobName}] Job execution completed: ${successful} successful, ${failed} failed, ${skipped} skipped`
    );

    return {
      total: installations.length,
      successful,
      failed,
      skipped,
    };
  }

  /**
   * Execute a job for a specific installation
   */
  async executeForInstallation(
    installationId: string,
    locationId: string,
    jobFunction: (context: JobContext) => Promise<JobRunResult>
  ): Promise<JobRunResult> {
    const jobRunId = await this.createJobRun(installationId);

    try {
      // Check if installation is active
      const isActive = await this.checkInstallationActive(installationId);
      if (!isActive) {
        const result: JobRunResult = {
          success: false,
          status: 'skipped',
          message: 'Installation is not active',
        };
        await this.updateJobRun(jobRunId, result);
        return result;
      }

      // Update job run to running
      await this.updateJobRunStatus(jobRunId, 'running');

      // Execute job with timeout
      const result = await this.executeWithTimeout(
        jobFunction({
          installationId,
          locationId,
          jobName: this.config.jobName,
          supabase: this.supabase,
        }),
        this.config.timeout!
      );

      // Update job run with result
      await this.updateJobRun(jobRunId, result);

      return result;
    } catch (error) {
      console.error(`[${this.config.jobName}] Job execution error:`, error);

      const result: JobRunResult = {
        success: false,
        status: 'failed',
        message: 'Job execution failed',
        error: error instanceof Error ? error.message : 'Unknown error',
      };

      await this.updateJobRun(jobRunId, result);

      return result;
    }
  }

  /**
   * Get all active installations
   */
  private async getActiveInstallations(): Promise<
    Array<{ id: string; location_id: string }>
  > {
    try {
      const { data, error } = await this.supabase
        .from('installations')
        .select('id, location_id')
        .eq('status', 'active')
        .eq('subscription_status', 'active');

      if (error) {
        console.error('Failed to fetch active installations:', error);
        throw new Error(`Failed to fetch active installations: ${error.message}`);
      }

      return data || [];
    } catch (error) {
      console.error('Error fetching active installations:', error);
      throw error;
    }
  }

  /**
   * Check if installation is active
   */
  private async checkInstallationActive(installationId: string): Promise<boolean> {
    try {
      const { data, error } = await this.supabase
        .from('installations')
        .select('status, subscription_status')
        .eq('id', installationId)
        .single();

      if (error) {
        console.error('Failed to check installation status:', error);
        return false;
      }

      const isActive = data.status === 'active' && data.subscription_status === 'active';

      if (!isActive) {
        console.log(
          `[${this.config.jobName}] Installation ${installationId} is not active: status=${data.status}, subscription=${data.subscription_status}`
        );
      }

      return isActive;
    } catch (error) {
      console.error('Error checking installation status:', error);
      return false;
    }
  }

  /**
   * Create a job run record
   */
  private async createJobRun(installationId: string): Promise<string> {
    try {
      const { data, error } = await this.supabase
        .from('job_runs')
        .insert({
          installation_id: installationId,
          job_name: this.config.jobName,
          status: 'pending',
          started_at: new Date().toISOString(),
        })
        .select('id')
        .single();

      if (error) {
        console.error('Failed to create job run:', error);
        throw new Error(`Failed to create job run: ${error.message}`);
      }

      return data.id;
    } catch (error) {
      console.error('Error creating job run:', error);
      throw error;
    }
  }

  /**
   * Update job run status
   */
  private async updateJobRunStatus(jobRunId: string, status: JobStatus): Promise<void> {
    try {
      const { error } = await this.supabase
        .from('job_runs')
        .update({ status })
        .eq('id', jobRunId);

      if (error) {
        console.error('Failed to update job run status:', error);
      }
    } catch (error) {
      console.error('Error updating job run status:', error);
    }
  }

  /**
   * Update job run with result
   */
  private async updateJobRun(jobRunId: string, result: JobRunResult): Promise<void> {
    try {
      const { error } = await this.supabase
        .from('job_runs')
        .update({
          status: result.status,
          completed_at: new Date().toISOString(),
          result: result.data || null,
          error: result.error || null,
        })
        .eq('id', jobRunId);

      if (error) {
        console.error('Failed to update job run:', error);
      }
    } catch (error) {
      console.error('Error updating job run:', error);
    }
  }

  /**
   * Execute function with timeout
   */
  private async executeWithTimeout<T>(
    promise: Promise<T>,
    timeoutMs: number
  ): Promise<T> {
    return Promise.race([
      promise,
      new Promise<T>((_, reject) =>
        setTimeout(() => reject(new Error('Job execution timeout')), timeoutMs)
      ),
    ]);
  }

  /**
   * Log audit event
   */
  async logAuditEvent(
    locationId: string,
    eventType: string,
    eventData: Record<string, any>
  ): Promise<void> {
    try {
      await this.supabase.rpc('log_audit_event', {
        loc_id: locationId,
        evt_type: eventType,
        evt_data: eventData,
      });
    } catch (error) {
      console.error('Failed to log audit event:', error);
    }
  }
}

/**
 * Verify Vercel Cron authentication
 */
export function verifyCronAuth(authHeader: string | null): boolean {
  const cronSecret = process.env.CRON_SECRET;

  if (!cronSecret) {
    console.error('CRON_SECRET is not configured');
    return false;
  }

  if (!authHeader) {
    console.error('No authorization header provided');
    return false;
  }

  const expectedAuth = `Bearer ${cronSecret}`;
  const isValid = authHeader === expectedAuth;

  if (!isValid) {
    console.error('Invalid cron authorization');
  }

  return isValid;
}