/**
 * Token Manager
 * 
 * Manages OAuth tokens for GoHighLevel API access
 * - Retrieves valid access tokens
 * - Refreshes expired tokens
 * - Updates tokens in database
 */

import { createClient } from '@supabase/supabase-js';

const supabaseUrl = process.env.NEXT_PUBLIC_SUPABASE_URL!;
const supabaseServiceKey = process.env.SUPABASE_SERVICE_ROLE_KEY!;

export class TokenManager {
  private supabase;

  constructor() {
    this.supabase = createClient(supabaseUrl, supabaseServiceKey);
  }

  /**
   * Get a valid access token for a location
   * Automatically refreshes if expired
   */
  async getValidAccessToken(locationId: string): Promise<string> {
    try {
      // Get installation for location
      const { data: installation, error } = await this.supabase
        .from('installations')
        .select('*')
        .eq('location_id', locationId)
        .eq('status', 'active')
        .single();

      if (error || !installation) {
        throw new Error(`Installation not found for location ${locationId}`);
      }

      // Check if token is expired or about to expire (within 5 minutes)
      const expiresAt = new Date(installation.expires_at);
      const now = new Date();
      const fiveMinutesFromNow = new Date(now.getTime() + 5 * 60 * 1000);

      if (expiresAt <= fiveMinutesFromNow) {
        console.log(`[TokenManager] Token expired or expiring soon for location ${locationId}, refreshing...`);
        return await this.refreshAccessToken(locationId);
      }

      return installation.access_token;
    } catch (error) {
      console.error('[TokenManager] Error getting access token:', error);
      throw error;
    }
  }

  /**
   * Refresh access token using refresh token
   */
  async refreshAccessToken(locationId: string): Promise<string> {
    try {
      // Get installation
      const { data: installation, error: fetchError } = await this.supabase
        .from('installations')
        .select('*')
        .eq('location_id', locationId)
        .single();

      if (fetchError || !installation) {
        throw new Error(`Installation not found for location ${locationId}`);
      }

      // Call GHL token refresh endpoint
      const response = await fetch('https://services.leadconnectorhq.com/oauth/token', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/x-www-form-urlencoded',
        },
        body: new URLSearchParams({
          client_id: process.env.GHL_CLIENT_ID!,
          client_secret: process.env.GHL_CLIENT_SECRET!,
          grant_type: 'refresh_token',
          refresh_token: installation.refresh_token,
        }),
      });

      if (!response.ok) {
        const errorText = await response.text();
        console.error('[TokenManager] Token refresh failed:', errorText);
        throw new Error(`Token refresh failed: ${response.status}`);
      }

      const tokenData = await response.json();

      // Calculate expiration time
      const expiresAt = new Date(Date.now() + tokenData.expires_in * 1000);

      // Update installation with new tokens
      const { error: updateError } = await this.supabase
        .from('installations')
        .update({
          access_token: tokenData.access_token,
          refresh_token: tokenData.refresh_token,
          expires_at: expiresAt.toISOString(),
          updated_at: new Date().toISOString(),
        })
        .eq('location_id', locationId);

      if (updateError) {
        console.error('[TokenManager] Failed to update tokens:', updateError);
        throw new Error('Failed to update tokens in database');
      }

      console.log(`[TokenManager] Token refreshed successfully for location ${locationId}`);

      // Log audit event
      await this.supabase.rpc('log_audit_event', {
        loc_id: locationId,
        evt_type: 'token_refreshed',
        evt_data: {
          expires_at: expiresAt.toISOString(),
        },
      });

      return tokenData.access_token;
    } catch (error) {
      console.error('[TokenManager] Error refreshing token:', error);
      throw error;
    }
  }

  /**
   * Check if token is valid (not expired)
   */
  async isTokenValid(locationId: string): Promise<boolean> {
    try {
      const { data: installation, error } = await this.supabase
        .from('installations')
        .select('expires_at')
        .eq('location_id', locationId)
        .single();

      if (error || !installation) {
        return false;
      }

      const expiresAt = new Date(installation.expires_at);
      const now = new Date();

      return expiresAt > now;
    } catch (error) {
      console.error('[TokenManager] Error checking token validity:', error);
      return false;
    }
  }
}