/**
 * GHL API Client with Rate Limiting and Retry Logic
 * 
 * Features:
 * - Rate limiting to respect GHL API limits
 * - Exponential backoff for failed requests
 * - Automatic token refresh
 * - Comprehensive error handling
 */

import { TokenManager } from './token-manager';

const GHL_API_BASE_URL = process.env.GHL_API_BASE_URL || 'https://services.leadconnectorhq.com';

export interface RateLimitConfig {
  maxRequestsPerSecond: number;
  maxRequestsPerMinute: number;
}

export interface RetryConfig {
  maxRetries: number;
  baseDelay: number; // milliseconds
  maxDelay: number; // milliseconds
}

export class GHLApiClient {
  private locationId: string;
  private tokenManager: TokenManager;
  private rateLimitConfig: RateLimitConfig;
  private retryConfig: RetryConfig;
  private requestQueue: Array<() => Promise<any>> = [];
  private isProcessingQueue = false;
  private lastRequestTime = 0;
  private requestCount = 0;
  private minuteRequestCount = 0;
  private minuteResetTime = Date.now();

  constructor(
    locationId: string,
    rateLimitConfig?: Partial<RateLimitConfig>,
    retryConfig?: Partial<RetryConfig>
  ) {
    this.locationId = locationId;
    this.tokenManager = new TokenManager();
    this.rateLimitConfig = {
      maxRequestsPerSecond: 10,
      maxRequestsPerMinute: 300,
      ...rateLimitConfig,
    };
    this.retryConfig = {
      maxRetries: 3,
      baseDelay: 1000,
      maxDelay: 30000,
      ...retryConfig,
    };
  }

  /**
   * Make an API request with rate limiting and retry logic
   */
  async request<T>(
    method: string,
    endpoint: string,
    body?: any,
    options?: RequestInit
  ): Promise<T> {
    return this.withRetry(async () => {
      await this.waitForRateLimit();

      const accessToken = await this.tokenManager.getValidAccessToken(this.locationId);

      const url = `${GHL_API_BASE_URL}${endpoint}`;
      const headers = {
        'Authorization': `Bearer ${accessToken}`,
        'Content-Type': 'application/json',
        'Version': '2021-07-28',
        ...options?.headers,
      };

      console.log(`[GHL API] ${method} ${endpoint}`);

      const response = await fetch(url, {
        method,
        headers,
        body: body ? JSON.stringify(body) : undefined,
        ...options,
      });

      this.updateRateLimitCounters();

      if (!response.ok) {
        const errorText = await response.text();
        console.error(`[GHL API] Error ${response.status}:`, errorText);

        // Handle rate limiting
        if (response.status === 429) {
          const retryAfter = response.headers.get('Retry-After');
          const delay = retryAfter ? parseInt(retryAfter) * 1000 : 60000;
          console.log(`[GHL API] Rate limited, waiting ${delay}ms`);
          await this.sleep(delay);
          throw new Error('Rate limited');
        }

        // Handle unauthorized (token expired)
        if (response.status === 401) {
          console.log('[GHL API] Token expired, refreshing...');
          await this.tokenManager.refreshAccessToken(this.locationId);
          throw new Error('Token expired');
        }

        throw new Error(`GHL API error: ${response.status} ${errorText}`);
      }

      const data = await response.json();
      return data as T;
    });
  }

  /**
   * GET request
   */
  async get<T>(endpoint: string, options?: RequestInit): Promise<T> {
    return this.request<T>('GET', endpoint, undefined, options);
  }

  /**
   * POST request
   */
  async post<T>(endpoint: string, body?: any, options?: RequestInit): Promise<T> {
    return this.request<T>('POST', endpoint, body, options);
  }

  /**
   * PUT request
   */
  async put<T>(endpoint: string, body?: any, options?: RequestInit): Promise<T> {
    return this.request<T>('PUT', endpoint, body, options);
  }

  /**
   * DELETE request
   */
  async delete<T>(endpoint: string, options?: RequestInit): Promise<T> {
    return this.request<T>('DELETE', endpoint, undefined, options);
  }

  /**
   * Fetch contacts from GHL
   */
  async getContacts(limit: number = 100, startAfter?: string): Promise<any> {
    let endpoint = `/contacts/?locationId=${this.locationId}&limit=${limit}`;
    if (startAfter) {
      endpoint += `&startAfter=${startAfter}`;
    }
    return this.get(endpoint);
  }

  /**
   * Fetch opportunities from GHL
   */
  async getOpportunities(pipelineId?: string, limit: number = 100): Promise<any> {
    let endpoint = `/opportunities/search?location_id=${this.locationId}&limit=${limit}`;
    if (pipelineId) {
      endpoint += `&pipelineId=${pipelineId}`;
    }
    return this.post(endpoint);
  }

  /**
   * Fetch pipelines from GHL
   */
  async getPipelines(): Promise<any> {
    return this.get(`/opportunities/pipelines?locationId=${this.locationId}`);
  }

  /**
   * Fetch custom fields from GHL
   */
  async getCustomFields(): Promise<any> {
    return this.get(`/locations/${this.locationId}/customFields`);
  }

  /**
   * Wait for rate limit
   */
  private async waitForRateLimit(): Promise<void> {
    const now = Date.now();

    // Reset minute counter if needed
    if (now - this.minuteResetTime >= 60000) {
      this.minuteRequestCount = 0;
      this.minuteResetTime = now;
    }

    // Check minute limit
    if (this.minuteRequestCount >= this.rateLimitConfig.maxRequestsPerMinute) {
      const waitTime = 60000 - (now - this.minuteResetTime);
      console.log(`[GHL API] Minute rate limit reached, waiting ${waitTime}ms`);
      await this.sleep(waitTime);
      this.minuteRequestCount = 0;
      this.minuteResetTime = Date.now();
    }

    // Check per-second limit
    const timeSinceLastRequest = now - this.lastRequestTime;
    const minDelay = 1000 / this.rateLimitConfig.maxRequestsPerSecond;

    if (timeSinceLastRequest < minDelay) {
      const waitTime = minDelay - timeSinceLastRequest;
      await this.sleep(waitTime);
    }
  }

  /**
   * Update rate limit counters
   */
  private updateRateLimitCounters(): void {
    this.lastRequestTime = Date.now();
    this.requestCount++;
    this.minuteRequestCount++;
  }

  /**
   * Retry a function with exponential backoff
   */
  private async withRetry<T>(fn: () => Promise<T>): Promise<T> {
    let lastError: Error | null = null;

    for (let attempt = 0; attempt <= this.retryConfig.maxRetries; attempt++) {
      try {
        return await fn();
      } catch (error) {
        lastError = error instanceof Error ? error : new Error('Unknown error');

        if (attempt === this.retryConfig.maxRetries) {
          break;
        }

        // Calculate delay with exponential backoff
        const delay = Math.min(
          this.retryConfig.baseDelay * Math.pow(2, attempt),
          this.retryConfig.maxDelay
        );

        console.log(
          `[GHL API] Attempt ${attempt + 1} failed, retrying in ${delay}ms...`
        );

        await this.sleep(delay);
      }
    }

    throw lastError;
  }

  /**
   * Sleep for a specified duration
   */
  private sleep(ms: number): Promise<void> {
    return new Promise(resolve => setTimeout(resolve, ms));
  }

  /**
   * Get rate limit stats
   */
  getRateLimitStats(): {
    requestCount: number;
    minuteRequestCount: number;
    lastRequestTime: number;
  } {
    return {
      requestCount: this.requestCount,
      minuteRequestCount: this.minuteRequestCount,
      lastRequestTime: this.lastRequestTime,
    };
  }
}