/**
 * Daily Sync Cron Job Route
 * 
 * Vercel Cron endpoint that runs the daily sync job
 * 
 * Schedule: Every day at 2 AM UTC (configured in vercel.json)
 * Authentication: Vercel Cron Secret (CRON_SECRET)
 */

import { NextRequest, NextResponse } from 'next/server';
import { JobRunner, verifyCronAuth } from '@/lib/utils/job-runner';
import { executeDailySync } from '@/lib/jobs/daily-sync.job';

export const dynamic = 'force-dynamic';
export const maxDuration = 300; // 5 minutes

/**
 * POST /api/cron/daily_sync
 * 
 * Executes the daily sync job for all active installations
 */
export async function POST(request: NextRequest) {
  console.log('[daily_sync] Cron job triggered');

  try {
    // Verify Vercel Cron authentication
    const authHeader = request.headers.get('authorization');
    if (!verifyCronAuth(authHeader)) {
      console.error('[daily_sync] Unauthorized cron request');
      return NextResponse.json(
        { error: 'Unauthorized' },
        { status: 401 }
      );
    }

    // Initialize job runner
    const jobRunner = new JobRunner({
      jobName: 'daily_sync',
      description: 'Daily sync of GHL data',
      timeout: 300000, // 5 minutes
      retryAttempts: 3,
    });

    // Execute job for all active installations
    const result = await jobRunner.executeForAllInstallations(executeDailySync);

    console.log('[daily_sync] Cron job completed:', result);

    return NextResponse.json({
      success: true,
      message: 'Daily sync completed',
      result,
    });
  } catch (error) {
    console.error('[daily_sync] Cron job error:', error);

    return NextResponse.json(
      {
        success: false,
        error: error instanceof Error ? error.message : 'Unknown error',
      },
      { status: 500 }
    );
  }
}

/**
 * GET /api/cron/daily_sync
 * 
 * Health check endpoint
 */
export async function GET() {
  return NextResponse.json({
    job: 'daily_sync',
    status: 'ready',
    description: 'Daily sync of GHL data',
  });
}